void *bridge_void_ptr_ptr(void *target_ptr)
{
    if (!target_ptr) {
        return nullptr;
    }
    std::lock_guard<std::mutex> lock(void_ptr_ptr_mutex);
    auto existing = void_ptr_ptr_index.find(target_ptr);
    if (existing != void_ptr_ptr_index.end()) {
        ++existing->second.refs;
        return reinterpret_cast<void *>(void_ptr_ptr_thunks[existing->second.index]);
    }
    uint32_t index;
    if (!void_ptr_ptr_free_slots.empty()) {
        index = void_ptr_ptr_free_slots.back();
        void_ptr_ptr_free_slots.pop_back();
    } else if (void_ptr_ptr_high_water < 32768) {
        index = void_ptr_ptr_high_water++;
    } else {
        fprintf(stderr,
                "FATAL: Havok callback bridge pool exhausted for the 'void_ptr_ptr' signature family:\n"
                "  All 32768 bridge slots are in use. Every distinct live native callback of this\n"
                "  signature consumes one slot; phantom/trigger volumes and other per-block callbacks\n"
                "  in worlds with very many grids/blocks can register more than the pool can hold.\n"
                "  Fix: raise this family in CALLBACK_SLOTS (currently 32768) in tools/generate_havok_wrapper.py,\n"
                "  regenerate the thunks (python3 tools/generate_havok_wrapper.py), and rebuild.\n");
        std::abort();
    }
    void_ptr_ptr_targets[index].store(reinterpret_cast<uintptr_t>(target_ptr), std::memory_order_release);
    void_ptr_ptr_index.emplace(target_ptr, void_ptr_ptr_slot{index, 1});
    return reinterpret_cast<void *>(void_ptr_ptr_thunks[index]);
}

void release_void_ptr_ptr(void *target_ptr)
{
    if (!target_ptr) {
        return;
    }
    std::lock_guard<std::mutex> lock(void_ptr_ptr_mutex);
    auto it = void_ptr_ptr_index.find(target_ptr);
    if (it == void_ptr_ptr_index.end()) {
        return;
    }
    if (--it->second.refs == 0) {
        uint32_t index = it->second.index;
        void_ptr_ptr_targets[index].store(0, std::memory_order_release);
        void_ptr_ptr_free_slots.push_back(index);
        void_ptr_ptr_index.erase(it);
    }
}
